'use client';

import { useRouter } from 'next/navigation';

export default function CrmLogout() {
  const router = useRouter();
  return (
    <button
      type="button"
      onClick={async () => {
        await fetch('/api/crm/logout', { method: 'POST' });
        router.push('/crm/login');
        router.refresh();
      }}
      className="text-sm text-gray-600 underline hover:text-primary"
    >
      Sign out
    </button>
  );
}
